// OAuth2 Implicit Flow Implementation for React SPA
class OAuth2ImplicitFlow {
  constructor(config) {
    this.clientId = config.clientId;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.scopes = config.scopes || 'openid profile email';
    this.state = this.generateState();
  }

  generateState() {
    return Math.random().toString(36).substring(2, 15) + 
           Math.random().toString(36).substring(2, 15);
  }

  getAuthUrl() {
    const params = new URLSearchParams({
      response_type: 'token',
      client_id: this.clientId,
      redirect_uri: this.redirectUri,
      scope: this.scopes,
      state: this.state
    });
    
    return `${this.authorizationEndpoint}?${params.toString()}`;
  }

  handleCallback() {
    const hash = window.location.hash.substring(1);
    const params = new URLSearchParams(hash);
    
    const accessToken = params.get('access_token');
    const tokenType = params.get('token_type');
    const expiresIn = params.get('expires_in');
    const state = params.get('state');
    
    // Security check: verify state parameter
    if (state !== this.state) {
      throw new Error('Invalid state parameter');
    }
    
    // Clear hash from URL
    window.history.replaceState({}, document.title, window.location.pathname);
    
    if (accessToken) {
      return {
        accessToken,
        tokenType,
        expiresIn: expiresIn ? parseInt(expiresIn) : null
      };
    }
    
    return null;
  }

  login() {
    window.location.href = this.getAuthUrl();
  }

  logout() {
    // Clear tokens from storage
    localStorage.removeItem('access_token');
    sessionStorage.removeItem('access_token');
  }

  // Secure token storage
  storeToken(tokenData) {
    // Use sessionStorage for short-lived tokens
    sessionStorage.setItem('access_token', tokenData.accessToken);
    sessionStorage.setItem('token_type', tokenData.tokenType);
    if (tokenData.expiresIn) {
      const expiresAt = Date.now() + (tokenData.expiresIn * 1000);
      sessionStorage.setItem('expires_at', expiresAt.toString());
    }
  }

  // Get stored token
  getStoredToken() {
    const token = sessionStorage.getItem('access_token');
    const expiresAt = sessionStorage.getItem('expires_at');
    
    if (token && expiresAt && Date.now() > parseInt(expiresAt)) {
      this.logout();
      return null;
    }
    
    return token;
  }

  // Validate token
  validateToken() {
    const token = this.getStoredToken();
    return !!token;
  }
}

// React Component Integration
const useOAuth2 = (config) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [token, setToken] = useState(null);
  const [loading, setLoading] = useState(false);
  
  const oauth = new OAuth2ImplicitFlow(config);
  
  useEffect(() => {
    // Check for callback tokens
    try {
      const tokenData = oauth.handleCallback();
      if (tokenData) {
        oauth.storeToken(tokenData);
        setToken(tokenData.accessToken);
        setIsAuthenticated(true);
      }
    } catch (error) {
      console.error('OAuth2 Error:', error);
    }
  }, []);
  
  const login = () => {
    setLoading(true);
    oauth.login();
  };
  
  const logout = () => {
    oauth.logout();
    setIsAuthenticated(false);
    setToken(null);
  };
  
  return {
    isAuthenticated,
    token,
    login,
    logout,
    loading
  };
};

// Usage in React Component
const App = () => {
  const config = {
    clientId: 'your-client-id',
    redirectUri: 'http://localhost:3000/callback',
    authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
    scopes: 'openid profile email'
  };
  
  const { isAuthenticated, token, login, logout, loading } = useOAuth2(config);
  
  if (loading) return <div>Loading...</div>;
  
  return (
    <div>
      {isAuthenticated ? (
        <div>
          <p>Logged in</p>
          <button onClick={logout}>Logout</button>
        </div>
      ) : (
        <button onClick={login}>Login</button>
      )}
    </div>
  );
};